To resolve the issue where data is not being deleted despite the button being clickable, I will harden the delete logic in two key areas: the central `handleDeleteEvent` in `PatientDetail.tsx` (which handles the Timeline and TPT tab) and the specific handlers in `HbvHcvTab.tsx`. I will also ensure the `z-index` of delete buttons is high enough to prevent any overlapping element from interfering with the click event.

Here are the updated files:

# Updated files:

## components/PatientDetail.tsx

I will update `handleDeleteEvent` to ensure it correctly identifies and removes both standard Medical History events and "Virtual Events" (HBV/HCV data shown on the timeline). I will also fix a potential issue where optional properties (like `hcvVlNotTested`) might be lost during the update.

```typescript
// ... existing code ...
  const handleDeleteEvent = (eventId: string) => {
    if (!window.confirm('คุณแน่ใจหรือไม่ว่าต้องการลบข้อมูลนี้? การกระทำนี้ไม่สามารถย้อนกลับได้')) {
        return;
    }

    let updatedPatient = { ...patient };
    let found = false;

    // Handle Virtual Events from HBV/HCV Tabs being deleted from Timeline
    if (eventId.startsWith('hbv-') || eventId.startsWith('hcv-')) {
        // Use safety fallbacks that preserve existing structure or default to empty arrays
        const hbvInfo = patient.hbvInfo || { hbsAgTests: [], viralLoads: [], ultrasounds: [], ctScans: [] };
        const hcvInfo = patient.hcvInfo || { hcvTests: [], preTreatmentVls: [], treatments: [], postTreatmentVls: [] };

        // HBV Parsers
        if (eventId.startsWith('hbv-hbsag-')) {
            const realId = eventId.replace('hbv-hbsag-', '');
            updatedPatient.hbvInfo = { ...hbvInfo, hbsAgTests: (hbvInfo.hbsAgTests || []).filter(x => x.id !== realId) };
            found = true;
        } else if (eventId.startsWith('hbv-vl-')) {
            const realId = eventId.replace('hbv-vl-', '');
            updatedPatient.hbvInfo = { ...hbvInfo, viralLoads: (hbvInfo.viralLoads || []).filter(x => x.id !== realId) };
            found = true;
        } else if (eventId.startsWith('hbv-us-')) {
            const realId = eventId.replace('hbv-us-', '');
            updatedPatient.hbvInfo = { ...hbvInfo, ultrasounds: (hbvInfo.ultrasounds || []).filter(x => x.id !== realId) };
            found = true;
        } else if (eventId.startsWith('hbv-ct-')) {
            const realId = eventId.replace('hbv-ct-', '');
            updatedPatient.hbvInfo = { ...hbvInfo, ctScans: (hbvInfo.ctScans || []).filter(x => x.id !== realId) };
            found = true;
        }
        // HCV Parsers
        else if (eventId.startsWith('hcv-test-')) {
            const realId = eventId.replace('hcv-test-', '');
            updatedPatient.hcvInfo = { ...hcvInfo, hcvTests: (hcvInfo.hcvTests || []).filter(x => x.id !== realId) };
            found = true;
        } else if (eventId.startsWith('hcv-prevl-')) {
            const realId = eventId.replace('hcv-prevl-', '');
            updatedPatient.hcvInfo = { ...hcvInfo, preTreatmentVls: (hcvInfo.preTreatmentVls || []).filter(x => x.id !== realId) };
            found = true;
        } else if (eventId.startsWith('hcv-treat-')) {
            const realId = eventId.replace('hcv-treat-', '');
            updatedPatient.hcvInfo = { ...hcvInfo, treatments: (hcvInfo.treatments || []).filter(x => x.id !== realId) };
            found = true;
        } else if (eventId.startsWith('hcv-postvl-')) {
            const realId = eventId.replace('hcv-postvl-', '');
            updatedPatient.hcvInfo = { ...hcvInfo, postTreatmentVls: (hcvInfo.postTreatmentVls || []).filter(x => x.id !== realId) };
            found = true;
        }

        if (found) {
            onUpdate(updatedPatient);
            return;
        }
    }

    // Default: Delete from Medical History (includes HIV, TPT, OI, etc.)
    // Ensure medicalHistory exists
    const currentHistory = patient.medicalHistory || [];
    const newHistory = currentHistory.filter(e => e.id !== eventId);

    // Only update if something actually changed (optional optimization, but good for debugging)
    if (newHistory.length !== currentHistory.length) {
        onUpdate({ ...patient, medicalHistory: newHistory });
    } else {
        // Fallback: If for some reason the ID wasn't found in history, 
        // it might be a sync issue, but we call update to force refresh just in case.
        console.warn("Event ID not found in medical history:", eventId);
        onUpdate({ ...patient, medicalHistory: newHistory });
    }
  };
// ... existing code ...
```

## components/tabs/HbvHcvTab.tsx

I will harden the local delete handlers in this tab to ensure they handle potentially undefined arrays gracefully and always trigger the update.

```typescript
// ... existing code ...
    const handleDeleteHbvRecord = (recordType: keyof Omit<HbvInfo, 'manualSummary'>, idToDelete: string) => {
        if (!window.confirm('คุณแน่ใจหรือไม่ว่าต้องการลบข้อมูลนี้?')) return;

        const currentHbvInfo = patient.hbvInfo || { hbsAgTests: [], viralLoads: [], ultrasounds: [], ctScans: [] };

        // Robustly get the array, defaulting to empty if undefined
        const existingRecords = (currentHbvInfo[recordType] as {id: string}[] | undefined) || [];

        const updatedRecords = existingRecords.filter(rec => rec.id !== idToDelete);

        // Construct new info, preserving other keys
        const newHbvInfo = { ...currentHbvInfo, [recordType]: updatedRecords };

        onUpdatePatient({ ...patient, hbvInfo: newHbvInfo });
    };
// ... existing code ...
    const handleDeleteHcvRecord = (recordType: keyof Omit<HcvInfo, 'hcvVlNotTested' | 'hcvTests'>, idToDelete: string) => {
        if (!window.confirm('คุณแน่ใจหรือไม่ว่าต้องการลบข้อมูลนี้?')) return;

        const currentHcvInfo = patient.hcvInfo || { hcvTests: [] };

        // Robustly get the array
        const existingRecords = ((currentHcvInfo[recordType] as unknown) as {id: string}[] | undefined) || [];

        const updatedRecords = existingRecords.filter(rec => rec.id !== idToDelete);

        const newHcvInfo = { ...currentHcvInfo, [recordType]: updatedRecords };

        onUpdatePatient({ ...patient, hcvInfo: newHcvInfo });
    };

     const handleDeleteHcvTest = (idToDelete: string) => {
        if (!window.confirm('คุณแน่ใจหรือไม่ว่าต้องการลบข้อมูลนี้?')) return;

        const currentHcvInfo = patient.hcvInfo || { hcvTests: [] };
        const currentTests = currentHcvInfo.hcvTests || [];

        const updatedTests = currentTests.filter(t => t.id !== idToDelete);

        onUpdatePatient({ ...patient, hcvInfo: { ...currentHcvInfo, hcvTests: updatedTests } });
    };
// ... existing code ...
